# Muqova generatsiya skripti
# Ishlatish: python3 cover.py "Avtor Ismi" "Kitob nomi" "Joy Yil" "chiqish_fayl.jpg"
#
# Misol:
# python3 cover.py "Mirzo Ulug'bek, Mo'tabarxon Turdaliyeva" "Chopildi" "Farg'ona 2026" "chopildi.jpg"
#
# Fon rasmi base64 ichida. Shrift fayllar (Gilroy-Light.ttf, Gilroy-Medium.ttf) shu papkada bo'lishi kerak.

import sys
import io
import base64
from pathlib import Path
from PIL import Image, ImageDraw, ImageFont

# Reference o'lcham (joylashuv shu asosda hisoblanadi) - o'zgartirmang
REF_W, REF_H = 417, 587

JPEG_SIFATI = 80  # 1-100. Kichik fayl <-> yuqori sifat muvozanati. 80 tavsiya etiladi.

SCRIPT_DIR = Path(__file__).parent

FON_BASE64 = """"""


def _matn_qator(draw, matn, font, max_kenglik):
    """Uzun matnni berilgan kenglikka sig'adigan satrlarga bo'ladi."""
    sozlar = matn.split()
    satrlar = []
    joriy = ""
    for soz in sozlar:
        sinov = (joriy + " " + soz).strip()
        bbox = draw.textbbox((0, 0), sinov, font=font)
        if bbox[2] - bbox[0] <= max_kenglik:
            joriy = sinov
        else:
            if joriy:
                satrlar.append(joriy)
            joriy = soz
    if joriy:
        satrlar.append(joriy)
    return satrlar or [""]


def muqova_yarat(avtor: str, kitob_nomi: str, joy_yil: str, chiqish_fayl: str):
    fon_bytes = base64.b64decode(FON_BASE64)

    bg = Image.open(io.BytesIO(fon_bytes)).convert("RGB")
    W, H = bg.size

    sx = W / REF_W
    sy = H / REF_H

    draw = ImageDraw.Draw(bg)

    font_kichik = ImageFont.truetype(str(SCRIPT_DIR / "Gilroy-Light.ttf"), int(13 * sy))
    font_sarlavha = ImageFont.truetype(str(SCRIPT_DIR / "Gilroy-Medium.ttf"), int(40 * sy))

    # Joy/Yil o'lchami avval hisoblanadi (avtor matnini cheklash uchun)
    joy_yil_w = 0
    if joy_yil:
        jy_bbox = draw.textbbox((0, 0), joy_yil, font=font_kichik)
        joy_yil_w = jy_bbox[2] - jy_bbox[0]

    # Avtor - yuqori chap (joy_yil bilan overlap bo'lmasligi uchun kenglik cheklanadi)
    if avtor:
        x_left = int(20 * sx)
        y_avtor = int(21 * sy)
        # Max avtor kengligi: joy_yil dan 16px chapda
        max_avtor_w = int(357 * sx) - joy_yil_w - int(30 * sx)
        avtor_text = avtor
        while avtor_text:
            bbox = draw.textbbox((0, 0), avtor_text, font=font_kichik)
            if bbox[2] - bbox[0] <= max_avtor_w:
                break
            avtor_text = avtor_text[:-1]
            if avtor_text.endswith(' ') or avtor_text.endswith(','):
                avtor_text = avtor_text[:-1] + '...'
                break
        draw.text((x_left, y_avtor), avtor_text, font=font_kichik, fill=(255, 255, 255))

    # Joy/Yil - yuqori o'ng (logodan chapda, o'ngga tekislangan)
    if joy_yil:
        x_joy_yil = int(357 * sx) - joy_yil_w
        y_joy_yil = int(21 * sy)
        draw.text((x_joy_yil, y_joy_yil), joy_yil, font=font_kichik, fill=(255, 255, 255))

    # Kitob nomi - katta sarlavha, wordwrap bilan
    x_sarlavha = int(20 * sx)
    y_sarlavha = int(112 * sy)
    max_kenglik = int((357 - 20) * sx)
    satr_balandligi = int(48 * sy)

    satrlar = _matn_qator(draw, kitob_nomi, font_sarlavha, max_kenglik)
    for i, satr in enumerate(satrlar):
        draw.text((x_sarlavha, y_sarlavha + i * satr_balandligi), satr, font=font_sarlavha, fill=(255, 255, 255))

    bg.save(chiqish_fayl, quality=JPEG_SIFATI, optimize=True)
    print(f"Tayyor: {chiqish_fayl}")


if __name__ == "__main__":
    if len(sys.argv) != 5:
        print('Ishlatish: python3 cover.py "Avtor" "Kitob nomi" "Joy Yil" "chiqish.jpg"')
        sys.exit(1)

    avtor, kitob_nomi, joy_yil, chiqish_fayl = sys.argv[1:5]
    muqova_yarat(avtor, kitob_nomi, joy_yil, chiqish_fayl)
